class Solution:
    def bagOfTokensScore(self, tokens, power: int) -> int:
        tokens = sorted(tokens)
        n = len(tokens)
        best = 0
        score = 0
        lo, hi = 0, n - 1
        while lo <= hi:
            if power >= tokens[lo]:
                power -= tokens[lo]
                score += 1
                lo += 1
                best = max(best, score)
            elif score > 0:
                power += tokens[hi]
                score -= 1
                hi -= 1
            else:
                break
        return best

