var bagOfTokensScore = function(tokens, power) {
    tokens.sort((a, b) => a - b);
    let lo = 0, hi = tokens.length - 1;
    let score = 0, best = 0;
    while (lo <= hi) {
        if (power >= tokens[lo]) {
            power -= tokens[lo++];
            score++;
            best = Math.max(best, score);
        } else if (score > 0 && lo < hi) {
            power += tokens[hi--];
            score--;
        } else {
            break;
        }
    }
    return best;
};
